#include <stdio.h>
#include <string.h>
#define NV 50257
#define NM 50000
unsigned char ut[256][3];int ul[256];
char mr[NM][80];int ml[NM];
char tk[NV][64];int tl[NV];
int L(char*s){int n=0;while(s[n])n++;return n;}
void ins(char*s,int n,int id){memcpy(tk[id],s,n);tl[id]=n;}
int find(char*s,int n,int max){for(int i=0;i<max;i++)if(tl[i]==n&&!memcmp(tk[i],s,n))return i;return -1;}
void uni(){int k=0;for(int i=0;i<256;i++){if((i>=33&&i<=126)||(i>=161&&i<=172)||(i>=174&&i<=255)){ut[i][0]=i;ul[i]=1;}else{int c=k+256;ut[i][0]=0xC0|(c>>6);ut[i][1]=0x80|(c&63);ul[i]=2;k++;}}}
void load_bpe(char*p){FILE*f=fopen(p,"rb");char ln[128];fgets(ln,128,f);for(int i=0;i<NM;i++){if(!fgets(ln,128,f))break;int n=L(ln);if(n&&ln[n-1]=='\n')n--;ln[n]=0;memcpy(mr[i],ln,n);ml[i]=n;}fclose(f);}
void build_vocab(){for(int i=0;i<256;i++)ins((char*)ut[i],ul[i],i);char g[3]={0xC4,0xA0,0};ins(g,2,256);int id=257;for(int i=0;i<NM&&id<50256;i++){char*p=mr[i],*q=strchr(p,' ');int n=ml[i];if(!q||(q-p)>=64||(n-(q-p+1))>=64)continue;char a[64],b[64];int la=q-p,lb=n-(q-p)-1;memcpy(a,p,la);a[la]=0;memcpy(b,q+1,lb);b[lb]=0;int ai=find(a,la,id),bi=find(b,lb,id);if(ai<0||bi<0)continue;char s[128];memcpy(s,tk[ai],tl[ai]);memcpy(s+tl[ai],tk[bi],tl[bi]);ins(s,tl[ai]+tl[bi],id);id++;}printf("built %d tokens\n",id);tk[50256][0]=0;tl[50256]=0;}
int rank(char*s,int n){for(int i=0;i<NM;i++)if(ml[i]==n&&!memcmp(mr[i],s,n))return i;return -1;}
int tid(char*s,int n){return find(s,n,NV);}
void enc(char*s,int n,int*ids,int*cnt){
 char p[1024][64];int pl[1024],c=0;
 for(int i=0;i<n;i++){memcpy(p[c],ut[(unsigned char)s[i]],ul[(unsigned char)s[i]]);pl[c++]=ul[(unsigned char)s[i]];}
 while(c>1){int bi=-1,br=1<<30;for(int i=0;i<c-1;i++){char mp[128];memcpy(mp,p[i],pl[i]);memcpy(mp+pl[i],p[i+1],pl[i+1]);int r=rank(mp,pl[i]+pl[i+1]);if(r>=0&&r<br){br=r;bi=i;}}if(bi<0)break;memcpy(p[bi]+pl[bi],p[bi+1],pl[bi+1]);pl[bi]+=pl[bi+1];for(int i=bi+1;i<c-1;i++){memcpy(p[i],p[i+1],64);pl[i]=pl[i+1];}c--;}
 *cnt=c;for(int i=0;i<c;i++)ids[i]=tid(p[i],pl[i]);
}
int main(int c,char**v){
 uni();load_bpe(v[1]);build_vocab();
 char*tests[]={"The"," answer"," is","The answer is","hello","discuss"};
 int n;int ids[64];
 for(int t=0;t<6;t++){enc(tests[t],L(tests[t]),ids,&n);printf("%s -> %d tokens:",tests[t],n);for(int i=0;i<n;i++)printf(" %d",ids[i]);printf("\n");}
 return 0;
}
EOF
